import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom'; // Import thêm Link

const HomePage = () => {
  const [products, setProducts] = useState([]);
  const [user, setUser] = useState(null); // Biến lưu thông tin người dùng
  const navigate = useNavigate();

  useEffect(() => {
    // 1. Lấy danh sách sản phẩm
    const fetchProducts = async () => {
      try {
        const { data } = await axios.get('http://localhost:5000/api/products');
        setProducts(data);
      } catch (error) {
        console.error("Lỗi kết nối:", error);
      }
    };
    fetchProducts();

    // 2. Kiểm tra xem đã đăng nhập chưa (Đọc từ bộ nhớ)
    const userInfo = localStorage.getItem('userInfo');
    if (userInfo) {
      setUser(JSON.parse(userInfo)); // Nếu có thì lưu vào biến user
    }
  }, []);

  // Hàm Đăng xuất
  const handleLogout = () => {
    localStorage.removeItem('userInfo'); // Xóa thẻ bài
    setUser(null); // Xóa biến user
    navigate('/login'); // Quay về trang đăng nhập
  };

  return (
    <div className="container py-4">
      {/* --- HEADER (THANH MENU) --- */}
      <header className="d-flex justify-content-between align-items-center mb-5 border-bottom pb-3">
        <h1 className="text-primary fw-bold">HaiHand Market</h1>
        
        <div>
          {user ? (
            // Giao diện KHI ĐÃ ĐĂNG NHẬP
            <div className="d-flex align-items-center gap-3">
              <span className="fw-bold text-dark">Xin chào, {user.name}!</span>
              <button className="btn btn-primary">Đăng tin</button>
              <button onClick={handleLogout} className="btn btn-outline-danger">Đăng xuất</button>
            </div>
          ) : (
            // Giao diện KHI CHƯA ĐĂNG NHẬP
            <div className="d-flex gap-2">
              <Link to="/login" className="btn btn-outline-primary">Đăng nhập</Link>
              <Link to="/register" className="btn btn-primary">Đăng ký</Link>
            </div>
          )}
        </div>
      </header>

      {/* --- DANH SÁCH SẢN PHẨM --- */}
      <h3 className="mb-4">🔥 Tin đăng mới nhất</h3>
      
      <div className="row">
        {products.length === 0 ? (
          <div className="col-12 text-center text-muted">
            <p>Chưa có sản phẩm nào.</p>
          </div>
        ) : null}

        {products.map((product) => (
          <div className="col-md-3 mb-4" key={product._id}>
            <div className="card h-100 shadow-sm border-0">
              <img 
                src={product.image} 
                className="card-img-top rounded-top" 
                alt={product.name} 
                style={{height: '200px', objectFit: 'cover'}}
              />
              <div className="card-body">
                <h5 className="card-title text-truncate">{product.name}</h5>
                <p className="card-text text-danger fw-bold fs-5">
                  {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price)}
                </p>
              </div>
              <div className="card-footer bg-white border-top-0 pb-3">
                 <button className="btn btn-outline-primary w-100">Xem chi tiết</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default HomePage;
